42	char compare_single_items(int item_idx1, int item_idx2) {
43	    if (item_idx1 == item_idx2) return '=';
44	
45	    std::pair<int, int> query_pair_key = {std::min(item_idx1, item_idx2), std::max(item_idx1, item_idx2)};
46	
47	    auto it = comparison_results_cache_1v1.find(query_pair_key);
48	    if (it != comparison_results_cache_1v1.end()) {
49	        char cached_res = it->second;
50	        if (item_idx1 == query_pair_key.first) return cached_res;
51	        return (cached_res == '<' ? '>' : (cached_res == '>' ? '<' : '='));
52	    }
53	
54	    if (queries_made >= Q_total_global) {
55	        return '=';
56	    }
57	
58	    char res_direct = perform_query_actual({item_idx1}, {item_idx2});
59	
60	    if (item_idx1 < item_idx2) {
61	        comparison_results_cache_1v1[query_pair_key] = res_direct;
62	    } else {
63	        char reversed_res = (res_direct == '<' ? '>' : (res_direct == '>' ? '<' : '='));
64	        comparison_results_cache_1v1[query_pair_key] = reversed_res;
65	    }
66	    return res_direct;
67	}
