335	                         estimated_weights[i] = std::max(1LL, w_p0 * w_p0 / w_p1);
336	                    } else {
337	                        estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
338	                    }
339	                } else {
340	                     estimated_weights[i] = std::max(1LL, w_p0 * FACTOR_LT_NUM / 100);
341	                }
342	            } else if (insert_pos_arr_idx == k_pivots_chosen) {
343	                long long w_pk_1 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen-1]];
344	                 if (k_pivots_chosen >= 2) {
345	                    long long w_pk_2 = estimated_weights[sorted_pivot_item_indices[k_pivots_chosen-2]];
346	                    if (w_pk_1 > w_pk_2 && w_pk_2 > 0 && w_pk_2 != 0) {
