    int n1 = mid - left + 1;
    int n2 = right - mid;
    std::vector<int> L_half(n1), R_half(n2);
    for (int i = 0; i < n1; i++) L_half[i] = items_to_sort[left + i];
    for (int j = 0; j < n2; j++) R_half[j] = items_to_sort[mid + 1 + j];

    int i = 0, j = 0, k = left;
    while (i < n1 && j < n2) {
        char cmp_res = compare_single_items(L_half[i], R_half[j]);
