        }
    }
    while (i < n1) items_to_sort[k++] = L_half[i++];
    while (j < n2) items_to_sort[k++] = R_half[j++];
}

void merge_sort_items(std::vector<int>& items_to_sort, int left, int right,
                      std::vector<std::vector<char>>& cmp_matrix) {
    if (left < right) {
        int mid = left + (right - left) / 2;
        merge_sort_items(items_to_sort, left, mid, cmp_matrix);
        merge_sort_items(items_to_sort, mid + 1, right, cmp_matrix);
        merge_for_sort(items_to_sort, left, mid, right, cmp_matrix);
    }
