    int k_pivots = N_items_global;
    if (sort_cost_estimate > Q_total_global * 0.7) {
        // Can't afford to sort all - use fewer pivots
        // Binary search for max k we can afford
        k_pivots = 1;
        for (int k = N_items_global; k >= 2; k--) {
