            int remaining_for_nonsort = (N_items_global - k) * (int)std::ceil(std::log2(std::max(2, k)));
            if (cost + remaining_for_nonsort <= (int)(Q_total_global * 0.85)) {
                k_pivots = k;
                break;
            }
        }
