    std::vector<int> all_items(N_items_global);
    std::iota(all_items.begin(), all_items.end(), 0);

    std::vector<int> pivot_items;
    std::vector<int> non_pivot_items;

    if (k_pivots >= N_items_global) {
        pivot_items = all_items;
        k_pivots = N_items_global;
    } else {
        std::shuffle(all_items.begin(), all_items.end(), rng_engine);
        pivot_items.assign(all_items.begin(), all_items.begin() + k_pivots);
        non_pivot_items.assign(all_items.begin() + k_pivots, all_items.end());
    }

    // Sort pivot items using merge sort
    std::vector<int> sorted_items = pivot_items;
    if (k_pivots > 1) {
        merge_sort_items(sorted_items, 0, k_pivots - 1, cmp_matrix);
    }

    // Binary search non-pivot items into sorted order
    std::vector<int> full_sorted; // all items sorted lightest to heaviest
    if (non_pivot_items.empty()) {
        full_sorted = sorted_items;
    } else {
        full_sorted = sorted_items;
        for (int np_item : non_pivot_items) {
            // Binary search for insertion position
            int lo = 0, hi = (int)full_sorted.size();
            while (lo < hi && queries_made < Q_total_global) {
                int mid = (lo + hi) / 2;
                char res;
                if (cmp_matrix[np_item][full_sorted[mid]] != 0) {
                    res = cmp_matrix[np_item][full_sorted[mid]];
                } else {
                    res = perform_query_actual({np_item}, {full_sorted[mid]});
                    cmp_matrix[np_item][full_sorted[mid]] = res;
                    cmp_matrix[full_sorted[mid]][np_item] = (res == '<' ? '>' : (res == '>' ? '<' : '='));
                }
                if (res == '<') {
                    hi = mid;
                } else if (res == '>') {
                    lo = mid + 1;
                } else {
                    lo = mid;
                    hi = mid;
                }
            }
            full_sorted.insert(full_sorted.begin() + lo, np_item);
        }
    }

    int N_sorted = (int)full_sorted.size();

    // --- Phase 2: Assign weights using exponential order statistics ---
    // For Exp(lambda=10^-5), E[X_(k:N)] = (1/lambda) * sum_{j=1}^{k} 1/(N-j+1)
    // where k is 1-indexed rank (k=1 is minimum)
    // We compute cumulative expected weights

    double lambda = 1e-5;
    double inv_lambda = 1.0 / lambda; // = 100000

    std::vector<double> expected_order_stats(N_sorted);
    double cumulative = 0.0;
    for (int k = 0; k < N_sorted; k++) {
        // k-th item (0-indexed, k=0 is lightest)
        // Expected spacing from previous: 1/(lambda * (N_sorted - k))
        // But use N_items_global as N since that's the actual population size
        double spacing = inv_lambda / (double)(N_items_global - k);
        cumulative += spacing;
        expected_order_stats[k] = cumulative;
    }

    std::vector<double> estimated_weights(N_items_global, 0.0);
    // Assign based on rank
    std::vector<int> item_rank(N_items_global, -1); // rank in sorted order (0=lightest)
    for (int k = 0; k < N_sorted; k++) {
        item_rank[full_sorted[k]] = k;
        estimated_weights[full_sorted[k]] = expected_order_stats[k];
    }

    // --- Phase 3: Use remaining queries for "1 vs group" ratio estimation ---
    // For the heaviest items, binary search: find k such that
    // sum(sorted[0]..sorted[k-1]) < sorted[heavy] < sum(sorted[0]..sorted[k])
    // This pins down the heavy item's weight relative to lighter items

    int queries_remaining = Q_total_global - queries_made;

    // Measure from heaviest down, each takes ~log2(N) queries
    int queries_per_measurement = std::max(1, (int)std::ceil(std::log2(std::max(2, N_sorted))));
    int num_items_to_measure = std::min(N_sorted - 1, queries_remaining / queries_per_measurement);
    // Focus on the top items (most impactful)
    num_items_to_measure = std::min(num_items_to_measure, N_sorted - 1);

    // Store measurement results: for each measured item, we know it's between
    // sum(sorted[0..lo-1]) and sum(sorted[0..hi-1])
    struct Measurement {
        int item_idx;
        int rank;
        int lo_count; // item > sum of lo_count lightest items
        int hi_count; // item < sum of hi_count lightest items (-1 if no upper bound)
    };
    std::vector<Measurement> measurements;

    for (int rank_idx = N_sorted - 1; rank_idx >= 1 && queries_made < Q_total_global; rank_idx--) {
        int heavy_item = full_sorted[rank_idx];

        // Binary search: find smallest k such that sum(sorted[0]..sorted[k-1]) >= heavy_item
        // We compare {heavy_item} vs {sorted[0], ..., sorted[k-1]}
        int lo = 1, hi = rank_idx; // at most rank_idx items lighter than this one
        int found_lo = 0; // heavy_item > sum of found_lo items
        int found_hi = -1; // heavy_item < sum of found_hi items (-1 = no bound)

        while (lo <= hi && queries_made < Q_total_global) {
            int mid = (lo + hi) / 2;
            // Compare heavy_item vs sum of mid lightest items
            std::vector<int> right_side;
            for (int j = 0; j < mid && j < rank_idx; j++) {
                right_side.push_back(full_sorted[j]);
            }
            if (right_side.empty()) {
                lo = mid + 1;
                continue;
            }

            char res = perform_query_actual({heavy_item}, right_side);

            if (res == '>') {
                found_lo = mid;
                lo = mid + 1;
            } else if (res == '<') {
                found_hi = mid;
                hi = mid - 1;
            } else {
                // Equal! Very precise
                found_lo = mid;
                found_hi = mid;
                break;
            }
        }

        measurements.push_back({heavy_item, rank_idx, found_lo, found_hi});

        // Budget check: stop if running low
        if (queries_made >= Q_total_global) break;
        // Limit measurements to avoid excessive time
        if ((int)measurements.size() >= num_items_to_measure) break;
    }

    // --- Phase 4: Refine weights using measurements ---
    // For each measurement, compute the sum of the lighter items and use as constraint
    // Process from lightest measured item to heaviest for consistency

    std::sort(measurements.begin(), measurements.end(), [](const Measurement& a, const Measurement& b) {
        return a.rank < b.rank;
    });

    for (const auto& m : measurements) {
        double sum_lo = 0.0, sum_hi = 0.0;

        if (m.lo_count > 0) {
            for (int j = 0; j < m.lo_count; j++) {
                sum_lo += estimated_weights[full_sorted[j]];
            }
        }
        if (m.hi_count > 0) {
            for (int j = 0; j < m.hi_count; j++) {
                sum_hi += estimated_weights[full_sorted[j]];
            }
        }

        double new_estimate;
        if (m.lo_count > 0 && m.hi_count > 0) {
            // Item weight is between sum_lo and sum_hi
            new_estimate = (sum_lo + sum_hi) / 2.0;
        } else if (m.hi_count > 0) {
            // Only upper bound
            new_estimate = sum_hi * 0.75;
        } else if (m.lo_count > 0) {
            // Only lower bound - item is heavier than sum of lo_count lightest
            // Use exponential prior to extrapolate
            double prior_estimate = expected_order_stats[m.rank];
            new_estimate = std::max(sum_lo * 1.3, prior_estimate);
        } else {
            // No measurement constraint, keep prior
            new_estimate = expected_order_stats[m.rank];
        }

        // Ensure monotonicity (item at higher rank should be heavier)
        if (m.rank > 0) {
            new_estimate = std::max(new_estimate, estimated_weights[full_sorted[m.rank - 1]]);
        }
        if (m.rank < N_sorted - 1) {
            new_estimate = std::min(new_estimate, estimated_weights[full_sorted[m.rank + 1]]);
        }

        estimated_weights[m.item_idx] = new_estimate;
    }

    // Ensure monotonicity across all items
    for (int k = 1; k < N_sorted; k++) {
        if (estimated_weights[full_sorted[k]] < estimated_weights[full_sorted[k-1]]) {
            estimated_weights[full_sorted[k]] = estimated_weights[full_sorted[k-1]];
        }
    }

    // Make sure all weights are positive
    for (int i = 0; i < N_items_global; i++) {
        if (estimated_weights[i] <= 0) estimated_weights[i] = 1.0;
    }

    // Exhaust remaining queries
    while (queries_made < Q_total_global) {
        int a = 0, b = 1;
        perform_query_actual({a}, {b});
    }

    // --- Assignment Phase: Guided SA with directed moves ---
    // Convert to long long for SA
    std::vector<long long> weights_ll(N_items_global);
    for (int i = 0; i < N_items_global; i++) {
        weights_ll[i] = std::max(1LL, (long long)std::round(estimated_weights[i]));
    }

    std::vector<int> items_sorted_desc(N_items_global);
    std::iota(items_sorted_desc.begin(), items_sorted_desc.end(), 0);
    std::sort(items_sorted_desc.begin(), items_sorted_desc.end(), [&](int a, int b) {
        return weights_ll[a] > weights_ll[b];
    });

    std::vector<int> assignment_array(N_items_global);
    std::vector<long long> group_sums_array(D_groups_global, 0);
    long long total_sum_est_val = 0;
    std::vector<std::vector<int>> group_items_indices(D_groups_global);

    // Snake/zigzag draft
    {
        int group_idx = 0;
        int direction = 1;
        for (int i = 0; i < N_items_global; i++) {
            int item_actual_idx = items_sorted_desc[i];
            assignment_array[item_actual_idx] = group_idx;
            group_sums_array[group_idx] += weights_ll[item_actual_idx];
            group_items_indices[group_idx].push_back(item_actual_idx);

            group_idx += direction;
            if (group_idx >= D_groups_global) {
                group_idx = D_groups_global - 1;
                direction = -1;
            } else if (group_idx < 0) {
                group_idx = 0;
                direction = 1;
            }
        }
    }

    for (int i = 0; i < N_items_global; i++) {
        total_sum_est_val += weights_ll[i];
    }

    // Also compute greedy LPT solution
    std::vector<int> greedy_assignment(N_items_global);
    std::vector<long long> greedy_group_sums(D_groups_global, 0);
    std::vector<std::vector<int>> greedy_group_items(D_groups_global);

    for (int i = 0; i < N_items_global; i++) {
        int item_actual_idx = items_sorted_desc[i];
        int best_grp = 0;
        long long min_sum = greedy_group_sums[0];
        for (int j = 1; j < D_groups_global; j++) {
            if (greedy_group_sums[j] < min_sum) {
                min_sum = greedy_group_sums[j];
                best_grp = j;
            }
        }
        greedy_assignment[item_actual_idx] = best_grp;
        greedy_group_sums[best_grp] += weights_ll[item_actual_idx];
        greedy_group_items[best_grp].push_back(item_actual_idx);
    }

    // Compare snake vs greedy
    double snake_sum_sq = 0, greedy_sum_sq = 0;
    for (int g = 0; g < D_groups_global; g++) {
        snake_sum_sq += (double)group_sums_array[g] * group_sums_array[g];
        greedy_sum_sq += (double)greedy_group_sums[g] * greedy_group_sums[g];
    }
    double snake_var = calculate_variance_from_sums(snake_sum_sq, (double)total_sum_est_val, D_groups_global);
    double greedy_var = calculate_variance_from_sums(greedy_sum_sq, (double)total_sum_est_val, D_groups_global);

    if (greedy_var < snake_var) {
        assignment_array = greedy_assignment;
        group_sums_array = greedy_group_sums;
        group_items_indices = greedy_group_items;
    }

    double current_sum_sq_group_totals = 0;
    for (long long s : group_sums_array) {
        current_sum_sq_group_totals += (double)s * s;
    }
    double current_var = calculate_variance_from_sums(current_sum_sq_group_totals, (double)total_sum_est_val, D_groups_global);

    std::vector<int> best_assignment = assignment_array;
    double best_var = current_var;

    // SA with guided moves
    double T_initial = std::max(1.0, current_var * 0.1);
    if (total_sum_est_val > 0 && current_var < 1e-9) {
        T_initial = std::max(1.0, (double)total_sum_est_val / std::max(1, N_items_global) * 0.1);
    }
    if (D_groups_global <= 1) T_initial = 0;

    double T = T_initial;
    double T_min = 1e-10;

    std::uniform_real_distribution<double> unif_dist(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N_items_global - 1);
    std::uniform_int_distribution<int> group_dist(0, D_groups_global - 1);

    int sa_iters_count = 0;
    const int CHECK_TIME_INTERVAL = 512;

    std::vector<int> item_pos_in_group_vector(N_items_global);
    for (int g = 0; g < D_groups_global; g++) {
        for (int pos = 0; pos < (int)group_items_indices[g].size(); pos++) {
            item_pos_in_group_vector[group_items_indices[g][pos]] = pos;
        }
    }

    while (D_groups_global > 1 && N_items_global > 0) {
        sa_iters_count++;
        if (sa_iters_count % CHECK_TIME_INTERVAL == 0) {
            auto time_now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(time_now - program_start_time) >= time_limit_ms) {
                break;
            }
            double elapsed_ms = std::chrono::duration_cast<std::chrono::microseconds>(time_now - program_start_time).count() / 1000.0;
            double progress = elapsed_ms / 1850.0;
            if (progress > 1.0) progress = 1.0;
            T = T_initial * std::pow(T_min / T_initial, progress);
        }

        if (T < 1e-15 && current_var < 1.0 + 1e-9) break;

        int move_choice = rng_engine() % 10;

        if (move_choice < 4) {
            // GUIDED RELOCATE
            int heavy_grp = 0, light_grp = 0;
            long long max_sum = group_sums_array[0], min_sum = group_sums_array[0];
            for (int g = 1; g < D_groups_global; g++) {
                if (group_sums_array[g] > max_sum) { max_sum = group_sums_array[g]; heavy_grp = g; }
                if (group_sums_array[g] < min_sum) { min_sum = group_sums_array[g]; light_grp = g; }
            }

            if (heavy_grp == light_grp || group_items_indices[heavy_grp].empty()) continue;

            long long target_w = (max_sum - min_sum) / 2;
            int best_item = -1;
            long long best_diff = LLONG_MAX;
            for (int item_idx : group_items_indices[heavy_grp]) {
                long long diff = std::abs(weights_ll[item_idx] - target_w);
                if (diff < best_diff) {
                    best_diff = diff;
                    best_item = item_idx;
                }
            }

            if (best_item == -1) continue;

            int item_to_move_idx = best_item;
            int old_grp_idx = heavy_grp;
            int new_grp_idx = light_grp;
            long long item_w_val = weights_ll[item_to_move_idx];

            long long old_sum_grp_A = group_sums_array[old_grp_idx];
            long long old_sum_grp_B = group_sums_array[new_grp_idx];
            long long new_sum_grp_A = old_sum_grp_A - item_w_val;
            long long new_sum_grp_B = old_sum_grp_B + item_w_val;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= (double)old_sum_grp_A*old_sum_grp_A + (double)old_sum_grp_B*old_sum_grp_B;
            new_sum_sq += (double)new_sum_grp_A*new_sum_grp_A + (double)new_sum_grp_B*new_sum_grp_B;
            double new_var = calculate_variance_from_sums(new_sum_sq, (double)total_sum_est_val, D_groups_global);

            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[old_grp_idx] = new_sum_grp_A;
                group_sums_array[new_grp_idx] = new_sum_grp_B;
                assignment_array[item_to_move_idx] = new_grp_idx;

                int pos = item_pos_in_group_vector[item_to_move_idx];
                int last = group_items_indices[old_grp_idx].back();
                if (item_to_move_idx != last) {
                    group_items_indices[old_grp_idx][pos] = last;
                    item_pos_in_group_vector[last] = pos;
                }
                group_items_indices[old_grp_idx].pop_back();
                group_items_indices[new_grp_idx].push_back(item_to_move_idx);
                item_pos_in_group_vector[item_to_move_idx] = group_items_indices[new_grp_idx].size() - 1;

                if (new_var < best_var) {
                    best_var = new_var;
                    best_assignment = assignment_array;
                }
            }
        } else if (move_choice < 6) {
            // GUIDED SWAP
            int heavy_grp = 0, light_grp = 0;
            long long max_sum = group_sums_array[0], min_sum = group_sums_array[0];
            for (int g = 1; g < D_groups_global; g++) {
                if (group_sums_array[g] > max_sum) { max_sum = group_sums_array[g]; heavy_grp = g; }
                if (group_sums_array[g] < min_sum) { min_sum = group_sums_array[g]; light_grp = g; }
            }

            if (heavy_grp == light_grp || group_items_indices[heavy_grp].empty() || group_items_indices[light_grp].empty()) continue;

            long long target_diff = (max_sum - min_sum) / 2;
            int best_h_item = -1, best_l_item = -1;
            long long best_diff = LLONG_MAX;

            int h_samples = std::min((int)group_items_indices[heavy_grp].size(), 8);
            int l_samples = std::min((int)group_items_indices[light_grp].size(), 8);

            for (int hi = 0; hi < h_samples; hi++) {
                int h_item = group_items_indices[heavy_grp][hi];
                for (int li = 0; li < l_samples; li++) {
                    int l_item = group_items_indices[light_grp][li];
                    long long w_diff = weights_ll[h_item] - weights_ll[l_item];
                    long long diff = std::abs(w_diff - target_diff);
                    if (diff < best_diff && w_diff > 0) {
                        best_diff = diff;
                        best_h_item = h_item;
                        best_l_item = l_item;
                    }
                }
            }

            if (best_h_item == -1 || best_l_item == -1) continue;

            int grp1_idx = heavy_grp;
            int grp2_idx = light_grp;
            int item1 = best_h_item;
            int item2 = best_l_item;
            long long w1 = weights_ll[item1];
            long long w2 = weights_ll[item2];

            long long old_sum_grp1 = group_sums_array[grp1_idx];
            long long old_sum_grp2 = group_sums_array[grp2_idx];
            long long new_sum_grp1 = old_sum_grp1 - w1 + w2;
            long long new_sum_grp2 = old_sum_grp2 - w2 + w1;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= (double)old_sum_grp1*old_sum_grp1 + (double)old_sum_grp2*old_sum_grp2;
            new_sum_sq += (double)new_sum_grp1*new_sum_grp1 + (double)new_sum_grp2*new_sum_grp2;
            double new_var = calculate_variance_from_sums(new_sum_sq, (double)total_sum_est_val, D_groups_global);

            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[grp1_idx] = new_sum_grp1;
                group_sums_array[grp2_idx] = new_sum_grp2;

                assignment_array[item1] = grp2_idx;
                assignment_array[item2] = grp1_idx;

                int pos1 = item_pos_in_group_vector[item1];
                int back1 = group_items_indices[grp1_idx].back();
                if (item1 != back1) {
                    group_items_indices[grp1_idx][pos1] = back1;
                    item_pos_in_group_vector[back1] = pos1;
                }
                group_items_indices[grp1_idx].pop_back();

                int pos2 = item_pos_in_group_vector[item2];
                int back2 = group_items_indices[grp2_idx].back();
                if (item2 != back2) {
                    group_items_indices[grp2_idx][pos2] = back2;
                    item_pos_in_group_vector[back2] = pos2;
                }
                group_items_indices[grp2_idx].pop_back();

                group_items_indices[grp2_idx].push_back(item1);
                item_pos_in_group_vector[item1] = group_items_indices[grp2_idx].size() - 1;

                group_items_indices[grp1_idx].push_back(item2);
                item_pos_in_group_vector[item2] = group_items_indices[grp1_idx].size() - 1;

                if (new_var < best_var) {
                    best_var = new_var;
                    best_assignment = assignment_array;
                }
            }
        } else if (move_choice < 8) {
            // RANDOM RELOCATE
            int item_to_move_idx = item_dist(rng_engine);
            int old_grp_idx = assignment_array[item_to_move_idx];
            int new_grp_idx = group_dist(rng_engine);
            if (new_grp_idx == old_grp_idx) continue;

            long long item_w_val = weights_ll[item_to_move_idx];

            long long old_sum_grp_A = group_sums_array[old_grp_idx];
            long long old_sum_grp_B = group_sums_array[new_grp_idx];
            long long new_sum_grp_A = old_sum_grp_A - item_w_val;
            long long new_sum_grp_B = old_sum_grp_B + item_w_val;

            double new_sum_sq = current_sum_sq_group_totals;
            new_sum_sq -= (double)old_sum_grp_A*old_sum_grp_A + (double)old_sum_grp_B*old_sum_grp_B;
            new_sum_sq += (double)new_sum_grp_A*new_sum_grp_A + (double)new_sum_grp_B*new_sum_grp_B;
            double new_var = calculate_variance_from_sums(new_sum_sq, (double)total_sum_est_val, D_groups_global);

            double delta_V = new_var - current_var;

            if (delta_V < 0 || (T > 1e-15 && unif_dist(rng_engine) < std::exp(-delta_V / T))) {
                current_var = new_var;
                current_sum_sq_group_totals = new_sum_sq;
                group_sums_array[old_grp_idx] = new_sum_grp_A;
                group_sums_array[new_grp_idx] = new_sum_grp_B;
                assignment_array[item_to_move_idx] = new_grp_idx;

                int pos = item_pos_in_group_vector[item_to_move_idx];
                int last = group_items_indices[old_grp_idx].back();
                if (item_to_move_idx != last) {
                    group_items_indices[old_grp_idx][pos] = last;
                    item_pos_in_group_vector[last] = pos;
                }
                group_items_indices[old_grp_idx].pop_back();
                group_items_indices[new_grp_idx].push_back(item_to_move_idx);
                item_pos_in_group_vector[item_to_move_idx] = group_items_indices[new_grp_idx].size() - 1;

                if (new_var < best_var) {
                    best_var = new_var;
                    best_assignment = assignment_array;
                }
            }
        } else {
            // RANDOM SWAP
            int grp1_idx = group_dist(rng_engine);
            int grp2_idx = group_dist(rng_engine);
            if (grp1_idx == grp2_idx) continue;
