std::chrono::steady_clock::time_point program_start_time;
std::chrono::milliseconds time_limit_ms(1850);

int N_items_global, D_groups_global, Q_total_global;
int queries_made = 0;

std::mt19937 rng_engine;

std::vector<std::vector<char>> cmp_matrix;

char perform_query_actual(const std::vector<int>& L_items, const std::vector<int>& R_items) {
    queries_made++;
    std::cout << L_items.size() << " " << R_items.size();
    for (int item_idx : L_items) std::cout << " " << item_idx;
    for (int item_idx : R_items) std::cout << " " << item_idx;
    std::cout << std::endl;
    char result_char;
    std::cin >> result_char;
    return result_char;
}

char compare_items(int a, int b) {
    if (a == b) return '=';
    if (cmp_matrix[a][b] != 0) return cmp_matrix[a][b];
    if (queries_made >= Q_total_global) return '=';
    char res = perform_query_actual({a}, {b});
    cmp_matrix[a][b] = res;
    cmp_matrix[b][a] = (res == '<' ? '>' : (res == '>' ? '<' : '='));
    return res;
}

void merge_for_sort(std::vector<int>& arr, int left, int mid, int right) {
    int n1 = mid - left + 1, n2 = right - mid;
    std::vector<int> L(n1), R(n2);
    for (int i = 0; i < n1; i++) L[i] = arr[left + i];
    for (int j = 0; j < n2; j++) R[j] = arr[mid + 1 + j];
    int i = 0, j = 0, k = left;
    while (i < n1 && j < n2) {
        char cmp = compare_items(L[i], R[j]);
        if (cmp == '<' || cmp == '=') arr[k++] = L[i++];
        else arr[k++] = R[j++];
    }
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}

void merge_sort(std::vector<int>& arr, int left, int right) {
    if (left < right) {
        int mid = (left + right) / 2;
        merge_sort(arr, left, mid);
        merge_sort(arr, mid + 1, right);
        merge_for_sort(arr, left, mid, right);
    }
}

double calculate_variance_from_sums(double sum_sq, double total, int D) {
    if (D <= 0) return 1e18;
    double mean = total / D;
    return std::max(0.0, sum_sq / D - mean * mean);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    program_start_time = std::chrono::steady_clock::now();
    rng_engine.seed(std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count());

    std::cin >> N_items_global >> D_groups_global >> Q_total_global;

    cmp_matrix.assign(N_items_global, std::vector<char>(N_items_global, 0));
    for (int i = 0; i < N_items_global; i++) cmp_matrix[i][i] = '=';

    // Budget planning
    // Sort cost: ~N*log2(N) for merge sort of N items
    // Weight measurement cost: ~log2(k) per item at rank k, total ~N*log2(N)/2
    // Binary search insertion of non-pivots: ~(N-k)*log2(k)

    int sort_budget = (int)(Q_total_global * 0.45);
    int measure_budget_total = Q_total_global - sort_budget;

    // Find max number of items we can sort within sort_budget
    int k_sort = N_items_global;
    for (int k = N_items_global; k >= 2; k--) {
        int cost = (int)(k * std::ceil(std::log2(std::max(2, k))));
        if (cost <= sort_budget) {
            k_sort = k;
            break;
        }
        if (k == 2) k_sort = 2;
    }
    k_sort = std::min(k_sort, N_items_global);

    // Select items to sort (use all if possible)
    std::vector<int> all_items(N_items_global);
    std::iota(all_items.begin(), all_items.end(), 0);

    std::vector<int> sort_items, non_sort_items;
    if (k_sort >= N_items_global) {
        sort_items = all_items;
    } else {
        std::shuffle(all_items.begin(), all_items.end(), rng_engine);
        sort_items.assign(all_items.begin(), all_items.begin() + k_sort);
        non_sort_items.assign(all_items.begin() + k_sort, all_items.end());
    }

    // Phase 1: Sort pivot items
    if (k_sort > 1) {
        merge_sort(sort_items, 0, k_sort - 1);
    }

    // Phase 2: Insert non-sort items into sorted order via binary search
    std::vector<int> sorted_all = sort_items;
    for (int np_item : non_sort_items) {
        int lo = 0, hi = (int)sorted_all.size();
        while (lo < hi && queries_made < Q_total_global) {
            int mid = (lo + hi) / 2;
            char res = compare_items(np_item, sorted_all[mid]);
            if (res == '<') hi = mid;
            else if (res == '>') lo = mid + 1;
            else { lo = mid; hi = mid; break; }
        }
        sorted_all.insert(sorted_all.begin() + lo, np_item);
    }

    int N_sorted = (int)sorted_all.size();

    // Phase 3: Bottom-up weight calibration using "1 vs group" measurements
    // For each item (starting from heavier ones), binary search for the number
    // of lightest items whose sum matches this item's weight.
    //
    // w[0] = 1 (base unit)
    // For item at rank k: find j such that sum(w[0]..w[j-1]) ~ w[k]
    // This gives w[k] = cumsum[j] (where cumsum is built from calibrated weights)

    std::vector<double> weights(N_items_global, 1.0);
    weights[sorted_all[0]] = 1.0;

    // Prefix sums of sorted items (by weight)
    std::vector<double> prefix_sum(N_sorted + 1, 0.0);
    prefix_sum[1] = 1.0;

    int queries_for_calibration = Q_total_global - queries_made;

    // For each item from rank 1 up, try to calibrate
    // Strategy: items at higher ranks get more queries (they matter more)
    // Budget: distribute remaining queries among items to measure

    // First, decide which items to measure and how many queries each gets
    // Items at higher rank are more important (heavier = more variance impact)
    // Each measurement costs log2(rank) queries via binary search

    for (int k = 1; k < N_sorted && queries_made < Q_total_global; k++) {
        int item_k = sorted_all[k];

        // Binary search: find j such that item_k ~ sum(sorted_all[0]..sorted_all[j-1])
        // Compare {item_k} vs {sorted_all[0], ..., sorted_all[j-1]}

        int lo = 1, hi = k; // j ranges from 1 to k (at most k lighter items)
        int found_lo = 0; // item_k > sum of found_lo lightest items
        int found_hi = -1; // item_k < sum of found_hi lightest items

        while (lo <= hi && queries_made < Q_total_global) {
            int mid = (lo + hi) / 2;

            // Build right side: the mid lightest items
            std::vector<int> right_side;
            for (int j = 0; j < mid; j++) {
                right_side.push_back(sorted_all[j]);
            }

            char res = perform_query_actual({item_k}, right_side);

            if (res == '>') {
                found_lo = mid;
                lo = mid + 1;
            } else if (res == '<') {
                found_hi = mid;
                hi = mid - 1;
            } else {
                found_lo = mid;
                found_hi = mid;
                break;
            }
        }

        // Assign weight based on measurement
        double w_k;
        if (found_lo > 0 && found_hi > 0) {
            if (found_lo == found_hi) {
                // Exact match: w[k] = sum(w[0]..w[found_lo-1])
                w_k = prefix_sum[found_lo];
            } else {
                // Between two bounds
                w_k = (prefix_sum[found_lo] + prefix_sum[found_hi]) / 2.0;
            }
        } else if (found_hi > 0) {
            // Only upper bound: w[k] < sum of found_hi items
            w_k = prefix_sum[found_hi] * 0.75;
        } else if (found_lo > 0) {
            // Only lower bound: w[k] > sum of found_lo items
            // Use exponential spacing expectation for extrapolation
            if (found_lo == k) {
                // Heavier than sum of ALL lighter items
                // Use expected ratio from exponential distribution
                // E[X_(k+1)] / E[sum X_(1..k)] for large k approaches 1/(k*lambda*mean_spacing)
                // Simple heuristic: multiply by (1 + 1/(N-k))
                w_k = prefix_sum[found_lo] * (1.0 + 1.0 / std::max(1, N_items_global - k));
            } else {
                w_k = prefix_sum[found_lo] * 1.2;
            }
        } else {
            // No measurement (ran out of queries)
            // Use exponential order statistic spacing
            // Expected w[k]/w[k-1] ratio for exponential ≈ (N-k+1)/(N-k) when items are close in rank
            w_k = weights[sorted_all[k-1]] * (double)(N_items_global - k + 1) / (double)(N_items_global - k);
        }

        // Ensure monotonicity
        w_k = std::max(w_k, weights[sorted_all[k-1]]);
        w_k = std::max(w_k, 1.0);

        weights[item_k] = w_k;
        prefix_sum[k + 1] = prefix_sum[k] + w_k;
    }

    // For any items that weren't calibrated (if we ran out of queries early)
    for (int k = 1; k < N_sorted; k++) {
        if (weights[sorted_all[k]] < weights[sorted_all[k-1]]) {
            weights[sorted_all[k]] = weights[sorted_all[k-1]];
        }
    }

    // Exhaust remaining queries
    while (queries_made < Q_total_global) {
        perform_query_actual({0}, {1 % N_items_global == 0 ? 1 : 1});
    }

    // --- Assignment Phase: Guided SA ---
    std::vector<long long> weights_ll(N_items_global);
    for (int i = 0; i < N_items_global; i++) {
        weights_ll[i] = std::max(1LL, (long long)std::round(weights[i]));
    }

    std::vector<int> items_sorted_desc(N_items_global);
    std::iota(items_sorted_desc.begin(), items_sorted_desc.end(), 0);
    std::sort(items_sorted_desc.begin(), items_sorted_desc.end(), [&](int a, int b) {
        return weights_ll[a] > weights_ll[b];
    });

    std::vector<int> assignment_array(N_items_global);
    std::vector<long long> group_sums_array(D_groups_global, 0);
    long long total_sum_est_val = 0;
    std::vector<std::vector<int>> group_items_indices(D_groups_global);

    // Snake draft
    {
        int group_idx = 0, direction = 1;
        for (int i = 0; i < N_items_global; i++) {
            int item = items_sorted_desc[i];
            assignment_array[item] = group_idx;
            group_sums_array[group_idx] += weights_ll[item];
            group_items_indices[group_idx].push_back(item);
            group_idx += direction;
            if (group_idx >= D_groups_global) { group_idx = D_groups_global - 1; direction = -1; }
            else if (group_idx < 0) { group_idx = 0; direction = 1; }
        }
    }
    for (int i = 0; i < N_items_global; i++) total_sum_est_val += weights_ll[i];

    // Greedy LPT
    std::vector<int> greedy_assignment(N_items_global);
    std::vector<long long> greedy_sums(D_groups_global, 0);
    std::vector<std::vector<int>> greedy_items(D_groups_global);
    for (int i = 0; i < N_items_global; i++) {
        int item = items_sorted_desc[i];
        int best_g = 0;
        for (int g = 1; g < D_groups_global; g++)
            if (greedy_sums[g] < greedy_sums[best_g]) best_g = g;
        greedy_assignment[item] = best_g;
        greedy_sums[best_g] += weights_ll[item];
        greedy_items[best_g].push_back(item);
    }

    // Pick better initial
    double snake_sq = 0, greedy_sq = 0;
    for (int g = 0; g < D_groups_global; g++) {
        snake_sq += (double)group_sums_array[g] * group_sums_array[g];
        greedy_sq += (double)greedy_sums[g] * greedy_sums[g];
    }
    if (greedy_sq < snake_sq) {
        assignment_array = greedy_assignment;
        group_sums_array = greedy_sums;
        group_items_indices = greedy_items;
    }

    double current_sum_sq = 0;
    for (long long s : group_sums_array) current_sum_sq += (double)s * s;
    double current_var = calculate_variance_from_sums(current_sum_sq, (double)total_sum_est_val, D_groups_global);

    std::vector<int> best_assignment = assignment_array;
    double best_var = current_var;

    // SA
    double T_initial = std::max(1.0, current_var * 0.1);
    if (current_var < 1e-9) T_initial = std::max(1.0, (double)total_sum_est_val / N_items_global * 0.1);
    if (D_groups_global <= 1) T_initial = 0;
    double T = T_initial, T_min = 1e-10;

    std::uniform_real_distribution<double> unif(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N_items_global - 1);
    std::uniform_int_distribution<int> group_dist(0, D_groups_global - 1);

