            auto now = std::chrono::steady_clock::now();
            if (std::chrono::duration_cast<std::chrono::milliseconds>(now - program_start_time) >= time_limit_ms) break;
            double elapsed = std::chrono::duration_cast<std::chrono::microseconds>(now - program_start_time).count() / 1000.0;
            double progress = elapsed / 1850.0;
            if (progress > 1.0) progress = 1.0;
            T = T_initial * std::pow(T_min / T_initial, progress);
        }
        if (T < 1e-15 && current_var < 1.0 + 1e-9) break;

        int move = rng_engine() % 10;
        if (move < 4) {
            // Guided relocate: heaviest group -> lightest group
            int hg = 0, lg = 0;
            for (int g = 1; g < D_groups_global; g++) {
                if (group_sums_array[g] > group_sums_array[hg]) hg = g;
                if (group_sums_array[g] < group_sums_array[lg]) lg = g;
            }
            if (hg == lg || group_items_indices[hg].empty()) continue;

            long long target = (group_sums_array[hg] - group_sums_array[lg]) / 2;
            int best_item = -1;
            long long best_diff = LLONG_MAX;
            for (int it : group_items_indices[hg]) {
                long long d = std::abs(weights_ll[it] - target);
                if (d < best_diff) { best_diff = d; best_item = it; }
            }
            if (best_item == -1) continue;

            long long w = weights_ll[best_item];
            long long oA = group_sums_array[hg], oB = group_sums_array[lg];
            long long nA = oA - w, nB = oB + w;
            double nsq = current_sum_sq - (double)oA*oA - (double)oB*oB + (double)nA*nA + (double)nB*nB;
            double nvar = calculate_variance_from_sums(nsq, (double)total_sum_est_val, D_groups_global);
            double delta = nvar - current_var;

            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = nvar; current_sum_sq = nsq;
                group_sums_array[hg] = nA; group_sums_array[lg] = nB;
                assignment_array[best_item] = lg;
                int p = item_pos[best_item];
                int last = group_items_indices[hg].back();
                if (best_item != last) { group_items_indices[hg][p] = last; item_pos[last] = p; }
                group_items_indices[hg].pop_back();
                group_items_indices[lg].push_back(best_item);
                item_pos[best_item] = group_items_indices[lg].size() - 1;
                if (nvar < best_var) { best_var = nvar; best_assignment = assignment_array; }
            }
        } else if (move < 6) {
            // Guided swap
            int hg = 0, lg = 0;
            for (int g = 1; g < D_groups_global; g++) {
                if (group_sums_array[g] > group_sums_array[hg]) hg = g;
                if (group_sums_array[g] < group_sums_array[lg]) lg = g;
            }
            if (hg == lg || group_items_indices[hg].empty() || group_items_indices[lg].empty()) continue;

            long long target = (group_sums_array[hg] - group_sums_array[lg]) / 2;
            int bh = -1, bl = -1;
            long long bd = LLONG_MAX;
            int hs = std::min((int)group_items_indices[hg].size(), 8);
            int ls = std::min((int)group_items_indices[lg].size(), 8);
            for (int i = 0; i < hs; i++) {
                int hi_item = group_items_indices[hg][i];
                for (int j = 0; j < ls; j++) {
                    int li_item = group_items_indices[lg][j];
                    long long wd = weights_ll[hi_item] - weights_ll[li_item];
                    if (wd > 0 && std::abs(wd - target) < bd) {
                        bd = std::abs(wd - target); bh = hi_item; bl = li_item;
                    }
                }
            }
            if (bh == -1) continue;

            long long w1 = weights_ll[bh], w2 = weights_ll[bl];
            long long o1 = group_sums_array[hg], o2 = group_sums_array[lg];
            long long n1 = o1 - w1 + w2, n2 = o2 - w2 + w1;
            double nsq = current_sum_sq - (double)o1*o1 - (double)o2*o2 + (double)n1*n1 + (double)n2*n2;
            double nvar = calculate_variance_from_sums(nsq, (double)total_sum_est_val, D_groups_global);
            double delta = nvar - current_var;

            if (delta < 0 || (T > 1e-15 && unif(rng_engine) < std::exp(-delta / T))) {
                current_var = nvar; current_sum_sq = nsq;
                group_sums_array[hg] = n1; group_sums_array[lg] = n2;
                assignment_array[bh] = lg; assignment_array[bl] = hg;

                int p1 = item_pos[bh], bk1 = group_items_indices[hg].back();
                if (bh != bk1) { group_items_indices[hg][p1] = bk1; item_pos[bk1] = p1; }
                group_items_indices[hg].pop_back();
