std::chrono::steady_clock::time_point program_start_time;
std::chrono::milliseconds time_limit_ms(1850);

int N_items_global, D_groups_global, Q_total_global;
int queries_made = 0;

std::mt19937 rng_engine;

std::vector<std::vector<char>> cmp_matrix;

char perform_query_actual(const std::vector<int>& L_items, const std::vector<int>& R_items) {
    queries_made++;
    std::cout << L_items.size() << " " << R_items.size();
    for (int item_idx : L_items) std::cout << " " << item_idx;
    for (int item_idx : R_items) std::cout << " " << item_idx;
    std::cout << std::endl;
    char result_char;
    std::cin >> result_char;
    return result_char;
}

char compare_items(int a, int b) {
    if (a == b) return '=';
    if (cmp_matrix[a][b] != 0) return cmp_matrix[a][b];
    if (queries_made >= Q_total_global) return '=';
    char res = perform_query_actual({a}, {b});
    cmp_matrix[a][b] = res;
    cmp_matrix[b][a] = (res == '<' ? '>' : (res == '>' ? '<' : '='));
    return res;
}

void merge_for_sort(std::vector<int>& arr, int left, int mid, int right) {
    int n1 = mid - left + 1, n2 = right - mid;
    std::vector<int> L(n1), R(n2);
    for (int i = 0; i < n1; i++) L[i] = arr[left + i];
    for (int j = 0; j < n2; j++) R[j] = arr[mid + 1 + j];
    int i = 0, j = 0, k = left;
    while (i < n1 && j < n2) {
        char cmp = compare_items(L[i], R[j]);
        if (cmp == '<' || cmp == '=') arr[k++] = L[i++];
        else arr[k++] = R[j++];
    }
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}

void merge_sort(std::vector<int>& arr, int left, int right) {
    if (left < right) {
        int mid = (left + right) / 2;
        merge_sort(arr, left, mid);
        merge_sort(arr, mid + 1, right);
        merge_for_sort(arr, left, mid, right);
    }
}

double calculate_variance_from_sums(double sum_sq, double total, int D) {
    if (D <= 0) return 1e18;
    double mean = total / D;
    return std::max(0.0, sum_sq / D - mean * mean);
}

double estimate_log2(double val) {
    if (val <= 1.0) return 0.0;
    return std::log2(val);
}

int calculate_estimated_query_cost(int N_val, int k_pivots_val) {
    if (k_pivots_val <= 0) return 0;
    if (k_pivots_val == 1) return (N_val > 1) ? (N_val - 1) : 0;
    double cost = 0;
    cost += (double)k_pivots_val * estimate_log2((double)k_pivots_val);
    for (int j = 2; j < k_pivots_val; ++j) {
        if (j-1 > 0) cost += estimate_log2((double)(j - 1));
    }
    cost += (double)(N_val - k_pivots_val) * estimate_log2((double)k_pivots_val);
    return (int)std::ceil(cost);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    program_start_time = std::chrono::steady_clock::now();
    rng_engine.seed(std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::steady_clock::now().time_since_epoch()).count());

    std::cin >> N_items_global >> D_groups_global >> Q_total_global;

    cmp_matrix.assign(N_items_global, std::vector<char>(N_items_global, 0));
    for (int i = 0; i < N_items_global; i++) cmp_matrix[i][i] = '=';

    // Phase 1: Determine how many pivots to sort
    int k_pivots = 1;
    if (N_items_global > 1) {
        for (int k = N_items_global; k >= 1; --k) {
            if (calculate_estimated_query_cost(N_items_global, k) <= Q_total_global) {
                k_pivots = k;
                break;
            }
        }
    }
    k_pivots = std::min(k_pivots, N_items_global);

    // Select pivots (random subset if not all)
    std::vector<int> all_items(N_items_global);
    std::iota(all_items.begin(), all_items.end(), 0);
    std::shuffle(all_items.begin(), all_items.end(), rng_engine);

    std::vector<int> pivot_items(all_items.begin(), all_items.begin() + k_pivots);
    std::set<int> pivot_set(pivot_items.begin(), pivot_items.end());

