    // Phase 2: Estimate gaps between consecutive sorted pivots using 1v2 binary search
    // For pivot j (j>=2), compare j vs (j-1 + s) to find how much bigger j is than j-1
    // The difference X_j is binary-searched among the existing pivots

    long long BASE_WEIGHT = 100000;
    std::vector<long long> est_weights(N_items_global, 0);

    if (k_pivots == 0) {
        for (int i = 0; i < N_items_global; i++) est_weights[i] = BASE_WEIGHT;
    } else if (k_pivots == 1) {
        est_weights[sorted_pivots[0]] = BASE_WEIGHT;
        for (int i = 0; i < N_items_global; i++) {
            if (i == sorted_pivots[0]) continue;
            char res = compare_items(i, sorted_pivots[0]);
            if (res == '=') est_weights[i] = BASE_WEIGHT;
            else if (res == '<') est_weights[i] = std::max(1LL, BASE_WEIGHT * 50 / 100);
            else est_weights[i] = std::max(1LL, BASE_WEIGHT * 200 / 100);
        }
    } else {
        // Assign weight to first pivot
        est_weights[sorted_pivots[0]] = BASE_WEIGHT;

        // Second pivot
        char res_p1 = compare_items(sorted_pivots[1], sorted_pivots[0]);
        if (res_p1 == '=') est_weights[sorted_pivots[1]] = BASE_WEIGHT;
        else if (res_p1 == '>') est_weights[sorted_pivots[1]] = BASE_WEIGHT * 200 / 100;
        else est_weights[sorted_pivots[1]] = BASE_WEIGHT;
        if (est_weights[sorted_pivots[1]] < est_weights[sorted_pivots[0]])
            est_weights[sorted_pivots[1]] = est_weights[sorted_pivots[0]];
        if (res_p1 == '>' && est_weights[sorted_pivots[1]] == est_weights[sorted_pivots[0]])
            est_weights[sorted_pivots[1]] = est_weights[sorted_pivots[0]] + 1;

        long long MAX_X_BOUND = BASE_WEIGHT * (1LL * N_items_global / std::max(1, D_groups_global) + 10);

        for (int j = 2; j < k_pivots; j++) {
            int curr = sorted_pivots[j];
            int prev = sorted_pivots[j-1];

            char res = compare_items(curr, prev);
            if (res == '=') {
                est_weights[curr] = est_weights[prev];
            } else if (res == '<') {
                est_weights[curr] = std::max(1LL, est_weights[prev] * 50 / 100);
            } else {
                // curr > prev: binary search for X_j using 1v2 comparisons
                int s_lo = 0, s_hi = j - 2;
                long long X_low = 1, X_high = MAX_X_BOUND;
                bool x_low_mod = false, x_high_mod = false;

                int num_candidates = s_hi - s_lo + 1;
                int bs_iters = 0;
                if (num_candidates > 0) bs_iters = std::max(1, (int)std::ceil(estimate_log2((double)num_candidates)));

                for (int it = 0; it < bs_iters && queries_made < Q_total_global; it++) {
                    if (s_lo > s_hi) break;
                    int s_mid = (s_lo + s_hi) / 2;
                    int aux_item = sorted_pivots[s_mid];

                    // Compare curr vs {prev, aux_item}
                    char r = perform_query_actual({curr}, {prev, aux_item});

                    if (r == '=') {
                        X_low = X_high = est_weights[aux_item];
                        x_low_mod = x_high_mod = true;
                        break;
                    } else if (r == '<') {
                        X_high = est_weights[aux_item];
                        x_high_mod = true;
                        s_hi = s_mid - 1;
                    } else {
                        X_low = est_weights[aux_item];
                        x_low_mod = true;
                        s_lo = s_mid + 1;
                    }
                }

                long long X_j;
                if (x_low_mod && x_high_mod) X_j = (X_low + X_high) / 2;
                else if (x_low_mod) X_j = X_low * 200 / 100;
                else if (x_high_mod) X_j = X_high * 50 / 100;
                else X_j = est_weights[prev] * 100 / 100;
                X_j = std::max(1LL, X_j);

                est_weights[curr] = est_weights[prev] + X_j;
            }
            if (est_weights[curr] < est_weights[prev]) est_weights[curr] = est_weights[prev];
            if (res == '>' && est_weights[curr] == est_weights[prev])
                est_weights[curr] = est_weights[prev] + 1;
        }

        // Phase 3: Place non-pivot items via binary search into sorted pivots
        for (int i = 0; i < N_items_global; i++) {
            if (pivot_set.count(i)) continue;

            int lo = 0, hi = k_pivots - 1;
            int found_eq = -1;

            while (lo <= hi && queries_made < Q_total_global) {
                int mid = (lo + hi) / 2;
                char res = compare_items(i, sorted_pivots[mid]);
                if (res == '=') { found_eq = mid; break; }
                else if (res == '<') hi = mid - 1;
                else lo = mid + 1;
            }

            if (found_eq != -1) {
                est_weights[i] = est_weights[sorted_pivots[found_eq]];
            } else {
                int insert_pos = lo;
                if (insert_pos == 0) {
                    long long w0 = est_weights[sorted_pivots[0]];
                    if (k_pivots >= 2) {
                        long long w1 = est_weights[sorted_pivots[1]];
                        if (w1 > w0 && w0 > 0) est_weights[i] = std::max(1LL, w0 * w0 / w1);
                        else est_weights[i] = std::max(1LL, w0 * 50 / 100);
                    } else est_weights[i] = std::max(1LL, w0 * 50 / 100);
                } else if (insert_pos >= k_pivots) {
                    long long wk1 = est_weights[sorted_pivots[k_pivots-1]];
                    if (k_pivots >= 2) {
                        long long wk2 = est_weights[sorted_pivots[k_pivots-2]];
                        if (wk1 > wk2 && wk2 > 0) est_weights[i] = std::max(1LL, wk1 * wk1 / wk2);
                        else est_weights[i] = std::max(1LL, wk1 * 200 / 100);
                    } else est_weights[i] = std::max(1LL, wk1 * 200 / 100);
                } else {
                    long long w_lo = est_weights[sorted_pivots[insert_pos-1]];
                    long long w_hi = est_weights[sorted_pivots[insert_pos]];
                    est_weights[i] = (long long)std::sqrt((double)w_lo * w_hi);
                    est_weights[i] = std::max(w_lo, est_weights[i]);
                    est_weights[i] = std::min(w_hi, est_weights[i]);
                }
            }
            if (est_weights[i] <= 0) est_weights[i] = 1;
        }
    }

    for (int i = 0; i < N_items_global; i++)
        if (est_weights[i] <= 0) est_weights[i] = BASE_WEIGHT;

    // Phase 4: Use remaining queries to refine heavy items via 1-vs-group
    // Build full sorted order (we already have sorted_pivots + insert positions for non-pivots)
    // Reconstruct full sorted order from known comparisons
    std::vector<int> full_sorted(N_items_global);
    std::iota(full_sorted.begin(), full_sorted.end(), 0);
    std::sort(full_sorted.begin(), full_sorted.end(), [&](int a, int b) {
        return est_weights[a] < est_weights[b];
    });

    // For the top items (heaviest), binary search: compare item vs sum of lightest items
    // to find how many light items it equals. This gives precise relative weight.
    int remaining = Q_total_global - queries_made;
    if (remaining > 0 && N_items_global > 1) {
        // prefix_sum[k] = sum of weights of sorted items 0..k-1 (using current estimates for sums)
        // But we want actual comparisons, not estimated sums!
        // Compare heavy_item vs {light_item_0, ..., light_item_{j-1}}
        // Binary search on j to find the crossover

        // Focus on heaviest items first (they dominate variance)
        for (int rank = N_items_global - 1; rank >= 1 && queries_made < Q_total_global; rank--) {
            int heavy_item = full_sorted[rank];

            // Binary search: find j such that heavy_item ~ sum(full_sorted[0..j-1])
            int lo = 1, hi = rank;
            int found_lo = 0, found_hi = -1;

            while (lo <= hi && queries_made < Q_total_global) {
                int mid = (lo + hi) / 2;
                std::vector<int> right_side;
                for (int j = 0; j < mid; j++) right_side.push_back(full_sorted[j]);

                char res = perform_query_actual({heavy_item}, right_side);
                if (res == '>') { found_lo = mid; lo = mid + 1; }
                else if (res == '<') { found_hi = mid; hi = mid - 1; }
                else { found_lo = found_hi = mid; break; }
            }

            // Compute sum of the found items using current estimates
            if (found_lo > 0 || found_hi > 0) {
                double sum_lo_est = 0, sum_hi_est = 0;
                if (found_lo > 0) {
                    for (int j = 0; j < found_lo; j++) sum_lo_est += est_weights[full_sorted[j]];
                }
                if (found_hi > 0 && found_hi != found_lo) {
                    for (int j = 0; j < found_hi; j++) sum_hi_est += est_weights[full_sorted[j]];
                }

                long long new_weight;
                if (found_lo > 0 && found_hi > 0 && found_lo == found_hi) {
                    new_weight = (long long)sum_lo_est;
                } else if (found_lo > 0 && found_hi > 0) {
                    new_weight = (long long)((sum_lo_est + sum_hi_est) / 2.0);
                } else if (found_hi > 0) {
                    new_weight = (long long)(sum_hi_est * 0.8);
                } else {
                    // found_lo > 0, no upper bound: heavier than sum of all lighter items
                    new_weight = (long long)(sum_lo_est * 1.3);
                }

                new_weight = std::max(new_weight, est_weights[full_sorted[rank-1]]);
                new_weight = std::max(1LL, new_weight);
                est_weights[heavy_item] = new_weight;
            }

            // Budget per item: ~log2(rank) queries
            // Stop if we've used enough or measured enough items
            int queries_per_item = (int)std::ceil(std::log2(std::max(2, rank)));
            if (Q_total_global - queries_made < queries_per_item) break;
        }
    }

    // Exhaust remaining queries
    while (queries_made < Q_total_global) {
        perform_query_actual({0}, {std::min(1, N_items_global - 1)});
    }

    // --- Assignment Phase: Guided SA ---
    std::vector<int> items_sorted_desc(N_items_global);
    std::iota(items_sorted_desc.begin(), items_sorted_desc.end(), 0);
    std::sort(items_sorted_desc.begin(), items_sorted_desc.end(), [&](int a, int b) {
        return est_weights[a] > est_weights[b];
    });

    std::vector<int> assignment(N_items_global);
    std::vector<long long> group_sums(D_groups_global, 0);
    long long total_sum = 0;
    std::vector<std::vector<int>> group_items(D_groups_global);

    // Snake draft
    {
        int g = 0, dir = 1;
        for (int i = 0; i < N_items_global; i++) {
            int item = items_sorted_desc[i];
            assignment[item] = g;
            group_sums[g] += est_weights[item];
            group_items[g].push_back(item);
            g += dir;
            if (g >= D_groups_global) { g = D_groups_global - 1; dir = -1; }
            else if (g < 0) { g = 0; dir = 1; }
        }
    }
    for (int i = 0; i < N_items_global; i++) total_sum += est_weights[i];

    // Greedy LPT
    std::vector<int> g_assign(N_items_global);
    std::vector<long long> g_sums(D_groups_global, 0);
    std::vector<std::vector<int>> g_items(D_groups_global);
    for (int i = 0; i < N_items_global; i++) {
        int item = items_sorted_desc[i];
        int bg = 0;
        for (int g = 1; g < D_groups_global; g++)
            if (g_sums[g] < g_sums[bg]) bg = g;
        g_assign[item] = bg;
        g_sums[bg] += est_weights[item];
        g_items[bg].push_back(item);
    }

    // Pick better initial
    double snake_sq = 0, greedy_sq = 0;
    for (int g = 0; g < D_groups_global; g++) {
        snake_sq += (double)group_sums[g] * group_sums[g];
        greedy_sq += (double)g_sums[g] * g_sums[g];
    }
    if (greedy_sq < snake_sq) {
        assignment = g_assign; group_sums = g_sums; group_items = g_items;
    }

    double sum_sq = 0;
    for (long long s : group_sums) sum_sq += (double)s * s;
    double cur_var = calculate_variance_from_sums(sum_sq, (double)total_sum, D_groups_global);

    std::vector<int> best_assign = assignment;
    double best_var = cur_var;

    // SA
    double T_init = std::max(1.0, cur_var * 0.1);
    if (cur_var < 1e-9) T_init = std::max(1.0, (double)total_sum / N_items_global * 0.1);
    if (D_groups_global <= 1) T_init = 0;
    double T = T_init, T_min = 1e-10;

    std::uniform_real_distribution<double> unif(0.0, 1.0);
    std::uniform_int_distribution<int> item_dist(0, N_items_global - 1);
    std::uniform_int_distribution<int> grp_dist(0, D_groups_global - 1);

    std::vector<int> ipos(N_items_global);
    for (int g = 0; g < D_groups_global; g++)
        for (int p = 0; p < (int)group_items[g].size(); p++)
            ipos[group_items[g][p]] = p;

    int iter = 0;
    while (D_groups_global > 1) {
        iter++;
        if (iter % 512 == 0) {
