        else arr[k++] = R[j++];
    }
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}

void merge_sort(std::vector<int>& arr, int left, int right) {
    if (left < right) {
        int mid = (left + right) / 2;
        merge_sort(arr, left, mid);
        merge_sort(arr, mid + 1, right);
        merge_for_sort(arr, left, mid, right);
    }
}

double calculate_variance_from_sums(double sum_sq, double total, int D) {
    if (D <= 0) return 1e18;
    double mean = total / D;
    return std::max(0.0, sum_sq / D - mean * mean);
}

double estimate_log2(double val) {
    if (val <= 1.0) return 0.0;
    return std::log2(val);
}

int calculate_estimated_query_cost(int N_val, int k_pivots_val) {
    if (k_pivots_val <= 0) return 0;
    if (k_pivots_val == 1) return (N_val > 1) ? (N_val - 1) : 0;
